import React, { useState, useEffect, FormEvent } from 'react';

interface Room {
  id: number;
  title: string;
  location: string;
  price: number;
  image: string;
  description: string;
}

interface User {
  id: number;
  name: string;
  email: string;
  password: string;
  bookings: number[]; // array with room ids
}

type Page = 'home' | 'detail' | 'login' | 'register' | 'myBookings';

export default function AirbnbMini(): JSX.Element {
  /* ------------------------------ Dummy Data ------------------------------ */
  const rooms: Room[] = [
    {
      id: 1,
      title: 'Cozy Loft with City View',
      location: 'New York, USA',
      price: 120,
      image:
        'https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?auto=format&fit=crop&w=800&q=60',
      description:
        'Enjoy a cozy stay in this modern loft located in the heart of Manhattan. Stunning skyline views included!'
    },
    {
      id: 2,
      title: 'Beachfront Bungalow',
      location: 'Tulum, Mexico',
      price: 150,
      image:
        'https://images.unsplash.com/photo-1507089947368-19c1da9775ae?auto=format&fit=crop&w=800&q=60',
      description:
        'Wake up to the sound of the waves in this charming bungalow right on the beach. Perfect for a relaxing getaway.'
    },
    {
      id: 3,
      title: 'Rustic Cabin in the Woods',
      location: 'Lake Tahoe, USA',
      price: 90,
      image:
        'https://images.unsplash.com/photo-1505693416424-2c3e5c463d31?auto=format&fit=crop&w=800&q=60',
      description:
        'Unplug and unwind in this rustic, yet comfortable cabin surrounded by pine trees and fresh mountain air.'
    }
  ];

  /* ------------------------------ State ------------------------------ */
  const [page, setPage] = useState<Page>('home');
  const [selectedRoom, setSelectedRoom] = useState<Room | null>(null);

  // Users & auth persisted in localStorage for demo purposes
  const [users, setUsers] = useState<User[]>(() => {
    const stored = localStorage.getItem('airbnb_users');
    return stored ? JSON.parse(stored) : [];
  });
  const [currentUserId, setCurrentUserId] = useState<number | null>(() => {
    const stored = localStorage.getItem('airbnb_currentUser');
    return stored ? JSON.parse(stored) : null;
  });

  /* ------------------------------ Effects ------------------------------ */
  useEffect(() => {
    localStorage.setItem('airbnb_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('airbnb_currentUser', JSON.stringify(currentUserId));
  }, [currentUserId]);

  /* ------------------------------ Helpers ------------------------------ */
  const currentUser: User | undefined = users.find((u) => u.id === currentUserId);

  const bookRoom = (roomId: number) => {
    if (!currentUser) {
      setPage('login');
      return;
    }
    if (currentUser.bookings.includes(roomId)) {
      alert('You already booked this room.');
      return;
    }
    const updated = users.map((u) =>
      u.id === currentUser.id ? { ...u, bookings: [...u.bookings, roomId] } : u
    );
    setUsers(updated);
    alert('Room booked successfully!');
    setPage('myBookings');
  };

  const logout = () => {
    setCurrentUserId(null);
    setPage('home');
  };

  /* ------------------------------ Forms ------------------------------ */
  const LoginForm = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');

    const onSubmit = (e: FormEvent) => {
      e.preventDefault();
      const user = users.find((u) => u.email === email && u.password === password);
      if (!user) {
        setError('Invalid credentials');
        return;
      }
      setCurrentUserId(user.id);
      setPage('home');
    };

    return (
      <form onSubmit={onSubmit} className="bg-white shadow-xl rounded-xl p-8 w-full max-w-md">
        <h2 className="text-2xl font-bold mb-6 text-center">Log in</h2>
        <input
          type="email"
          required
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          className="w-full mb-4 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
        />
        <input
          type="password"
          required
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          className="w-full mb-6 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
        />
        {error && <p className="text-red-500 mb-4 text-sm text-center">{error}</p>}
        <button
          type="submit"
          className="w-full bg-purple-600 hover:bg-purple-700 text-white font-semibold py-2 rounded-lg transition-all duration-300"
        >
          Enter
        </button>
        <p className="text-center text-sm mt-4">
          No account?
          <button
            type="button"
            className="text-purple-600 ml-1 hover:underline"
            onClick={() => setPage('register')}
          >
            Register here
          </button>
        </p>
      </form>
    );
  };

  const RegisterForm = () => {
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');

    const onSubmit = (e: FormEvent) => {
      e.preventDefault();
      if (users.some((u) => u.email === email)) {
        setError('Email already registered');
        return;
      }
      const newUser: User = {
        id: Date.now(),
        name,
        email,
        password,
        bookings: []
      };
      setUsers([...users, newUser]);
      setCurrentUserId(newUser.id);
      setPage('home');
    };

    return (
      <form onSubmit={onSubmit} className="bg-white shadow-xl rounded-xl p-8 w-full max-w-md">
        <h2 className="text-2xl font-bold mb-6 text-center">Register</h2>
        <input
          type="text"
          required
          placeholder="Name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="w-full mb-4 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
        />
        <input
          type="email"
          required
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          className="w-full mb-4 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
        />
        <input
          type="password"
          required
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          className="w-full mb-6 px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
        />
        {error && <p className="text-red-500 mb-4 text-sm text-center">{error}</p>}
        <button
          type="submit"
          className="w-full bg-purple-600 hover:bg-purple-700 text-white font-semibold py-2 rounded-lg transition-all duration-300"
        >
          Create account
        </button>
        <p className="text-center text-sm mt-4">
          Already have an account?
          <button
            type="button"
            className="text-purple-600 ml-1 hover:underline"
            onClick={() => setPage('login')}
          >
            Log in
          </button>
        </p>
      </form>
    );
  };

  /* ------------------------------ UI Pieces ------------------------------ */
  const Navbar = () => (
    <nav className="bg-white shadow-md sticky top-0 z-10">
      <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
        <button
          className="text-xl font-extrabold text-purple-600 hover:opacity-80 transition"
          onClick={() => {
            setPage('home');
            setSelectedRoom(null);
          }}
        >
          airclonb
        </button>
        <div className="space-x-4 text-sm">
          {currentUser ? (
            <>
              <span className="hidden sm:inline">Hello, {currentUser.name.split(' ')[0]}</span>
              <button
                className="hover:underline"
                onClick={() => setPage('myBookings')}
              >
                My bookings
              </button>
              <button
                className="hover:underline text-red-500"
                onClick={logout}
              >
                Logout
              </button>
            </>
          ) : (
            <>
              <button className="hover:underline" onClick={() => setPage('login')}>Log in</button>
              <button className="hover:underline" onClick={() => setPage('register')}>Register</button>
            </>
          )}
        </div>
      </div>
    </nav>
  );

  const RoomCard = ({ room }: { room: Room }) => (
    <div
      onClick={() => {
        setSelectedRoom(room);
        setPage('detail');
      }}
      className="cursor-pointer bg-white rounded-xl shadow-md hover:shadow-xl transition-all overflow-hidden"
    >
      <img src={room.image} alt={room.title} className="h-48 w-full object-cover" />
      <div className="p-4">
        <h3 className="font-semibold text-lg mb-1">{room.title}</h3>
        <p className="text-gray-500 text-sm mb-2">{room.location}</p>
        <p className="font-bold">
          $ {room.price}
          <span className="font-normal text-sm text-gray-500"> /night</span>
        </p>
      </div>
    </div>
  );

  /* ------------------------------ Pages ------------------------------ */
  const HomePage = () => (
    <div className="max-w-6xl mx-auto p-6 grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {rooms.map((r) => (
        <RoomCard key={r.id} room={r} />
      ))}
    </div>
  );

  const DetailPage = () => (
    <>
      {selectedRoom && (
        <div className="max-w-4xl mx-auto p-6 grid md:grid-cols-2 gap-6">
          <img src={selectedRoom.image} alt={selectedRoom.title} className="rounded-xl w-full h-64 object-cover md:h-full" />
          <div>
            <h2 className="text-3xl font-bold mb-2">{selectedRoom.title}</h2>
            <p className="text-gray-600 mb-4">{selectedRoom.location}</p>
            <p className="mb-6 text-sm text-gray-700">{selectedRoom.description}</p>
            <p className="text-xl font-bold mb-6">$ {selectedRoom.price} / night</p>
            <button
              className="bg-purple-600 hover:bg-purple-700 text-white font-semibold px-6 py-2 rounded-lg transition"
              onClick={() => bookRoom(selectedRoom.id)}
            >
              Book now
            </button>
          </div>
        </div>
      )}
    </>
  );

  const MyBookingsPage = () => {
    if (!currentUser || currentUser.bookings.length === 0)
      return (
        <div className="p-10 text-center text-gray-600">No bookings yet.</div>
      );

    const bookedRooms = rooms.filter((r) => currentUser.bookings.includes(r.id));

    return (
      <div className="max-w-6xl mx-auto p-6 grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {bookedRooms.map((r) => (
          <div key={r.id} className="bg-white rounded-xl shadow-md overflow-hidden">
            <img src={r.image} alt={r.title} className="h-40 w-full object-cover" />
            <div className="p-4">
              <h3 className="font-semibold text-lg mb-1">{r.title}</h3>
              <p className="text-gray-500 text-sm mb-2">{r.location}</p>
              <p className="font-bold">$ {r.price} /night</p>
            </div>
          </div>
        ))}
      </div>
    );
  };

  /* ------------------------------ Render ------------------------------ */
  return (
    <div className="font-sans min-h-screen bg-gray-100 flex flex-col">
      <Navbar />
      <main className="flex-grow">
        {page === 'home' && <HomePage />}
        {page === 'detail' && <DetailPage />}
        {page === 'login' && (
          <div className="flex justify-center items-center py-12 px-4">
            <LoginForm />
          </div>
        )}
        {page === 'register' && (
          <div className="flex justify-center items-center py-12 px-4">
            <RegisterForm />
          </div>
        )}
        {page === 'myBookings' && <MyBookingsPage />}
      </main>
      <footer className="text-center py-6 text-sm text-gray-500">
        Made with ❤️ using React + Tailwind
      </footer>
    </div>
  );
}
